import { RouteMeta } from '@ditsmod/rest';
import type { XOperationObject } from '@ts-stack/openapi-spec';

/**
 * This metadata is generated by `RestRouteExtension`, and available via DI per
 * a route.
 */
export class OasExtensionRouteMeta extends RouteMeta {
  operationObject?: XOperationObject;
  /**
   * Path in format of OpenAPI Specefication, (e.g. `posts/{postId}/comments/{commentId}`).
   */
  oasPath?: string;
}
